create table dirkspzm32.aps_order_auftr_pos_info (
    sid                varchar2(2 char) default '01' not null enable,
    firma_nr           number(2, 0) default 1 not null enable,
    aps_plan_status    varchar2(3 char) not null enable,
    aps_stufe          number(*, 0) not null enable,
    aps_info_zeitpunkt varchar2(30 char) not null enable,
    auftrag_nr         number(*, 0) not null enable,
    pos_nr             number(*, 0) not null enable,
    upos_nr            number(*, 0) not null enable,
    pos_info           varchar2(4000 char) not null enable,
    erz_datum          date not null enable,
    erz_login_id       number(*, 0) not null enable,
    aend_datum         date,
    aend_login_id      number(*, 0)
);

alter table dirkspzm32.aps_order_auftr_pos_info
    add constraint pk_aps_order_auftr_pos_info
        primary key ( aps_stufe,
                      aps_info_zeitpunkt,
                      auftrag_nr,
                      pos_nr,
                      upos_nr,
                      aps_plan_status,
                      firma_nr,
                      sid )
            using index enable;


